const SUPABASE_URL = $env.SUPABASE_URL || $env.NEXT_PUBLIC_SUPABASE_URL;
const SERVICE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SERVICE_KEY) {
  throw new Error('Missing SUPABASE_URL/NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY');
}

const headers = {
  apikey: SERVICE_KEY,
  Authorization: 'Bearer ' + SERVICE_KEY,
  'Content-Type': 'application/json',
};

async function read(path) {
  const r = await fetch(SUPABASE_URL + path, { headers });
  const txt = await r.text();
  if (!r.ok) throw new Error(path + ' failed (' + r.status + '): ' + txt);
  return txt ? JSON.parse(txt) : [];
}

const latestDateRows = await read('/rest/v1/kpi_timeseries?select=captured_for_date&window_type=eq.daily&order=captured_for_date.desc&limit=1');
const latestDate = latestDateRows[0]?.captured_for_date || new Date().toISOString().slice(0, 10);

const [kpis, approvals, emails, changes, deals, integrations] = await Promise.all([
  read('/rest/v1/kpi_timeseries?select=metric_name,value,window_type,captured_for_date&window_type=eq.daily&captured_for_date=eq.' + latestDate + '&order=metric_name.asc&limit=50'),
  read('/rest/v1/approvals?select=id,requesting_agent_id,summary,permission_tier,risk_level,confidence,requested_at,action_type&status=eq.pending&order=permission_tier.desc,requested_at.asc&limit=10'),
  read('/rest/v1/email_events?select=sender_email,summary,suggested_action,priority,status,received_at&priority=in.(critical,important)&status=in.(new,triaged)&order=received_at.desc&limit=5'),
  read('/rest/v1/open_brain_entries?select=title,summary_text,department,priority,created_at,source_agent_id&priority=in.(critical,important)&order=created_at.desc&limit=20'),
  read('/rest/v1/deals?select=account_name,stage,territory,updated_at&stage=in.(prospect,contacted,negotiating,terms_agreed,contract,active)&order=updated_at.desc&limit=10'),
  read('/rest/v1/integration_health?select=service_name,system_name,status,connection_status,updated_at&limit=30')
]);

const criticalAlerts = [];
const degraded = [];
for (const i of integrations) {
  const state = i.status || i.connection_status || 'not_configured';
  if (state === 'error' || state === 'degraded' || state === 'down' || state === 'expired') {
    degraded.push(i.service_name || i.system_name);
  }
}

if (degraded.length > 0) {
  criticalAlerts.push({ source: 'integration_health', message: 'Data degraded for: ' + degraded.join(', '), severity: 'important' });
}

const briefing = {
  briefing_date: latestDate,
  financial_pulse: {
    key_metrics: kpis.slice(0, 8),
  },
  decisions_pending: approvals.slice(0, 5).map((a) => ({ agent_id: a.requesting_agent_id, summary: a.summary, tier: a.permission_tier, urgency: a.risk_level || 'medium' })),
  critical_alerts: criticalAlerts.slice(0, 3),
  email_highlights: emails.slice(0, 3).map((e) => ({ sender: e.sender_email, summary: e.summary || 'No summary', suggested_action: e.suggested_action || null })),
  changes_24h: changes.slice(0, 5).map((c) => ({ description: c.title || c.summary_text || 'Change detected', department: c.department || 'unknown', source_agent: c.source_agent_id || null })),
  deal_status: deals.slice(0, 3).map((d) => ({ account: d.account_name, stage: d.stage, movement: 'active', next_action: 'Review with owner' })),
  biggest_risk: degraded.length > 0 ? ('Integration degradation: ' + degraded.join(', ')) : 'No critical system degradation detected.',
  biggest_opportunity: approvals.length > 0 ? 'Clear pending approvals to unblock agent throughput.' : 'Maintain clean queue and continue KPI consistency.',
  integration_status: {
    connected: integrations.filter((i) => (i.status || i.connection_status) === 'healthy' || (i.status || i.connection_status) === 'connected').length,
    total: integrations.length,
    degraded
  }
};

return [{ json: { briefing, generated_at: new Date().toISOString() } }];
